INSERT INTO `crm_customer_follow` (`customer_id`, `follow_user_id`, `follow_user_name`, `follow_type`, `follow_content`, `next_follow_time`, `next_follow_remark`, `is_last`) VALUES
(1, 1, '管理员', 4, '拜访航天科技集团，与吴燕生董事长进行了深入交流。客户对我们的企业管理系统表示浓厚兴趣，特别是在项目管理和数据分析方面的需求。约定下周进行详细演示和方案沟通。', '2026-04-28 10:00:00', '准备详细演示方案，重点展示项目管理模块', 1),
(2, 1, '管理员', 1, '电话跟进国家电网信息化部门。王敏副总经理表示正在进行数字化转型项目招标，我们的方案已经进入第二轮。需要准备更详细的技术方案和案例分享。', '2026-04-29 14:00:00', '准备技术方案和案例资料', 1),
(3, 1, '管理员', 2, '微信沟通华为余承东总。对方表示对我们的库存管理模块非常感兴趣，特别是针对供应链优化的功能。建议安排产品经理进行深度沟通。', '2026-04-27 11:00:00', '安排产品经理对接', 1),
(4, 1, '管理员', 1, '电话联系阿里巴巴张勇总。对方表示对我们的客户关系管理系统有需求，但目前他们有自己的系统。需要了解更详细的差异化优势。', '2026-04-30 09:30:00', '准备差异化优势分析报告', 1),
(5, 1, '管理员', 4, '拜访腾讯马化腾总。对方对我们的数据分析和可视化展示功能表示认可。建议先进行小范围试点，再决定是否全面推广。', '2026-05-05 15:00:00', '准备试点方案', 1),
(6, 1, '管理员', 3, '邮件发送给字节跳动张利东总，包含产品报价和详细方案。等待对方回复。', '2026-04-26 16:00:00', '跟进邮件回复情况', 1),
(7, 1, '管理员', 1, '电话沟通美团穆荣均总。对方表示正在进行供应商评估，我们的方案已入围。需要准备演示环境。', '2026-04-28 09:00:00', '准备演示环境', 1),
(8, 1, '管理员', 2, '微信沟通京东刘强东总。对方表示对我们的仓储管理系统有兴趣，但需要更详细的成本分析。', '2026-04-29 10:00:00', '准备成本分析报告', 1),
(9, 1, '管理员', 4, '拜访小米雷军总。对方对我们的智能制造解决方案非常感兴趣，特别是在生产执行系统方面。约定进行深入技术交流。', '2026-05-08 14:00:00', '安排技术团队交流', 1),
(10, 1, '管理员', 1, '电话跟进百度李彦宏总。对方表示正在评估多个供应商，我们的AI相关功能有一定优势。需要准备更多AI案例。', '2026-04-27 11:30:00', '准备AI应用案例', 1);
